// Aktuelles Datum
const today = new Date();

// Berechnung des Enddatums (letzter Tag vor dem aktuellen Datum)
const end = new Date(today);
end.setDate(today.getDate() - 1);

// Berechnung des Startdatums (7 Tage vor dem Enddatum)
const start = new Date(end);
start.setDate(end.getDate() - 0);

// Formatierung zu YYYYMMDD
function formatDate(date) {
    const year = date.getFullYear();
    const month = String(date.getMonth() + 1).padStart(2, '0');
    const day = String(date.getDate()).padStart(2, '0');
    return `${year}-${month}-${day}`;
}

// Ausgabe
const startDate = formatDate(start);
const endDate = formatDate(end);

return { startDate, endDate };

// Função para formatar valores monetários no formato brasileiro
function formatCurrency(value) {
  return `R$ ${value.toFixed(2).replace('.', ',')}`;
}

function dataDeOntem() {
  return new Date(Date.now() - 86400000).toISOString().substring(0, 10);
}

// Função para adicionar o emoji com base no score
function getEmoji(score) {
  if (score > 80) {
    return "🟢";
  } else if (score > 70) {
    return "🟡";
  } else {
    return "🔴";
  }
}

// Gera a mensagem para uma única conta, dado o array de results
function generateMessageForAccount(results) {
  // Não precisamos mais extrair customerId aqui para o retorno,
  // pois faremos isso no loop principal.
  const customerName = results[0]?.customer?.descriptiveName || "Cliente Desconhecido";
  // const customerId   = results[0]?.customer?.id              || "ID Desconhecido"; // Removido daqui

  let totalCostMicros       = 0;
  let totalOptimizationScore = 0;
  const campaignMessages    = [];

  results.forEach(item => {
    const campaignName      = item.campaign?.name || "Campanha Desconhecida";
    const costMicros        = parseInt(item.metrics?.costMicros || "0", 10);
    const optimizationScore = item.campaign?.optimizationScore || 0;

    totalCostMicros       += costMicros;
    totalOptimizationScore += optimizationScore;

    campaignMessages.push(
      `- ${campaignName}: ${formatCurrency(costMicros / 1e6)} (${(optimizationScore * 100).toFixed(0)}% ${getEmoji(optimizationScore * 100)})`
    );
  });

  const avgScore = (totalOptimizationScore / results.length) * 100;
  const emoji    = getEmoji(avgScore);

  // Monta um cabeçalho por conta e anexa as campanhas
  return [
    `**Cliente: ${customerName} (`+dataDeOntem()+`)**`, // Removido o ID daqui da mensagem
    `Total gasto: ${formatCurrency(totalCostMicros / 1e6)}`,
    `Score Otimização: ${avgScore.toFixed(0)}% ${emoji}`,
    ...campaignMessages
  ].join("\n");
}

// === início do nó n8n ===
const inputData = $input.all();  // captura TODOS os itens de entrada
const output    = [];

inputData.forEach(item => {
  // só processa itens que tenham um array "results" válido
  if (Array.isArray(item.json?.results) && item.json.results.length > 0) {
    try {
      // Extrai o customerId diretamente do primeiro resultado
      const accountId = item.json.results[0]?.customer?.id || "ID Desconhecido";

      const msg = generateMessageForAccount(item.json.results)+"\n________";

      // Adiciona o accountId ao objeto de saída
      output.push({ json: { message: msg, accountId: accountId } });
    } catch (err) {
      // Tenta obter o ID mesmo em caso de erro para incluir na mensagem de erro
      const accountIdOnError = item.json?.results?.[0]?.customer?.id || "ID Desconhecido";
      output.push({ json: { error: `Erro ao processar conta (ID: ${accountIdOnError}): ${err.message}`, accountId: accountIdOnError } });
    }
  }
  // Note: Este código original não lidava com contas SEM resultados.
  // Se você precisa lidar com contas sem resultados (como no seu exemplo anterior com o nó "Sort"),
  // você precisará da lógica do código anterior que usava o mapa de resultados.
  // Este código atual apenas processa os itens que JÁ VÊM COM results.
});

// retorna um array de objetos, cada um com sua própria mensagem e ID
return output;

